 * minimum target size — and well below the 2.5.5 (AAA) / platform 44×44 guidance.
 * For a hover-gated trigger this is doubly punishing on touch, so the hit area
 * is enlarged to >= 24×24 (preferably ~32px) by raising the padding and adding
 * explicit min-width / min-height, WITHOUT changing the glyph's visual size
 * (font-size/line-height stay 16px / 1) and without regressing the chromeless
 * look or the opacity/pointer-events reveal behavior.
 *
 * As throughout this file the raw stylesheet is parsed (the vitest env does not
 * load app.css, so getComputedStyle cannot observe author rules). We read the
 * numeric min-width / min-height and compute the rendered box height from
 * font-size × line-height + vertical padding, asserting each axis >= 24px.
 * ========================================================================= */
describe('src/app.css — "⋮" trigger hit area meets WCAG 2.5.8 minimum (>= 24×24)', () => {
  const WCAG_AA_MIN = 24; // CSS px, WCAG 2.5.8 (AA) Target Size Minimum

  /**
   * Read the value (in px) of a `prop: <n>px` declaration on a rule block.
   * Anchored on a preceding start-of-block or `;` so a prop name cannot match a
   * suffix of another property (e.g. `min-width` will never match `max-width`).
   * Returns null when the property is absent.
   */
  function pxValue(decls: string, prop: string): number | null {
    const re = new RegExp(`(?:^|;)\\s*${prop}\\s*:\\s*([0-9]+)px`, 'm');
    const m = decls.match(re);
    return m ? Number(m[1]) : null;
  }

  /** First (vertical) value of a `padding: <v>px [<h>px]?` declaration. */
  function verticalPaddingPx(decls: string): number {
    const m = decls.match(/padding\s*:\s*([0-9]+)px(?:\s+[0-9]+px)?/);
    return m ? Number(m[1]) : 0;
  }

  let btn: string;
  beforeAll(() => {
    btn = ruleDeclarations(/\.row-menu-btn/)!;
    expect(btn, 'a base .row-menu-btn { ... } rule must exist').not.toBeNull();
  });

  it('declares a min-width >= 24px so the box is never narrower than the minimum', () => {
    const mw = pxValue(btn, 'min-width');
    expect(mw, '.row-menu-btn must declare a px min-width (floor on tap width)').not.toBeNull();
    expect(mw!, 'min-width must be >= 24px (WCAG 2.5.8 AA)').toBeGreaterThanOrEqual(WCAG_AA_MIN);
  });

  it('declares a min-height >= 24px so the box is never shorter than the minimum', () => {
    const mh = pxValue(btn, 'min-height');
    expect(mh, '.row-menu-btn must declare a px min-height (floor on tap height)').not.toBeNull();
    expect(mh!, 'min-height must be >= 24px (WCAG 2.5.8 AA)').toBeGreaterThanOrEqual(WCAG_AA_MIN);
  });

  it('renders a box >= 24px tall from font-size × line-height + vertical padding', () => {
    // The trigger's content height is line-height(1) × font-size, grown by the
    // vertical padding; the box height is the max of that and min-height. This
    // pins the EFFECTIVE hit height regardless of which mechanism delivers it.
    const fontSize = pxValue(btn, 'font-size') ?? 0;
    const lh = btn.match(/line-height\s*:\s*([0-9.]+)/);
    const lineHeight = lh ? Number(lh[1]) : 1; // unitless multiplier; default 1
    const minH = pxValue(btn, 'min-height') ?? 0;
    const boxHeight = Math.max(fontSize * lineHeight + verticalPaddingPx(btn) * 2, minH);
    expect(
      boxHeight,
      `rendered hit-box height must be >= 24px (got ${boxHeight}px from font-size ${fontSize}px, ` +
        `line-height ${lineHeight}, padding ${verticalPaddingPx(btn)}px, min-height ${minH}px)`,
    ).toBeGreaterThanOrEqual(WCAG_AA_MIN);
  });

  it('keeps the visual glyph size unchanged while enlarging the target', () => {
    // The hit-area fix must NOT change the glyph itself: font-size stays 16px
    // and line-height stays 1.
    expect(pxValue(btn, 'font-size'), 'font-size stays 16px (glyph not resized)').toBe(16);
    expect(btn, 'line-height stays 1').toMatch(/line-height\s*:\s*1\s*;/);
  });

  it('preserves the chromeless look and idle reveal behavior after enlarging', () => {
    // The size change must not regress the other base-rule contracts.
    expect(/background\s*:\s*none/.test(btn), 'background:none preserved').toBe(true);
    expect(/border\s*:\s*none/.test(btn), 'border:none preserved').toBe(true);
    expect(/border-radius\s*:\s*4px/.test(btn), 'border-radius:4px preserved').toBe(true);
    expect(/cursor\s*:\s*pointer/.test(btn), 'cursor:pointer preserved').toBe(true);
    expect(/pointer-events\s*:\s*none/.test(btn), 'pointer-events:none at rest preserved').toBe(
      true,
    );
    const op = btn.match(/opacity\s*:\s*([0-9.]+)/);
    expect(op, 'opacity declared on the base rule').not.toBeNull();
    expect(Number(op![1]), 'opacity stays suppressed (<1) at rest').toBeLessThan(1);
  });
});

/* ===========================================================================
 * Row action "⋮" button — touch / coarse-pointer operability
 *
 * The base `.row-menu-btn` rule keeps the trigger suppressed at rest
 * (`opacity: 0.35; pointer-events: none`) and reveals it only via row hover,
 * keyboard focus, or an open popup. That is a desktop aesthetic that assumes a
 * precise, hover-capable pointer — and it is DEAD on a touch device:
 * `pointer-events: none` blocks ALL pointer input (including touch taps), so a
 * phone/tablet user can SEE the faintly-visible ⋮ but cannot tap it, and the
 * reveal conditions (which require first interacting with the button or its
 * row) can never fire (WCAG 2.5.1 / 2.5.8).
 *
 * The fix contract pinned here: a `(hover: none)` / `(pointer: coarse)` media
 * query lifts the button to fully visible AND tappable AT REST on devices
 * without a hover-capable pointer, while desktop keeps the reveal-on-hover
 * behavior (the base rule is unchanged — still tested above). The crux is
 * `pointer-events: auto` inside that media query; `opacity: 1` is the matching
 * visibility half.
 * ========================================================================= */
describe('src/app.css — row action "⋮" button touch operability (coarse pointer)', () => {
  it('defines an @media rule targeting coarse-pointer / touch devices', () => {
    const body = coarsePointerMediaQueryBody();
    expect(
      body,
      'an @media rule targeting (hover: none) and/or (pointer: coarse) must exist so the ' +
        '⋮ button is operable on touch devices that have no hover-capable pointer',
    ).not.toBeNull();
  });

  it('lists (pointer: coarse) in the media condition, not only (hover: none)', () => {
    // `(hover: none)` alone misses devices/emulation that report a hover-
    // capable primary pointer but a COARSE one (e.g. touch laptops, or browser
    // coarse-pointer emulation). The condition must ALSO include
    // `(pointer: coarse)` so the reveal fires for any coarse-pointer device.
    // We read the matching @media condition text directly from the stylesheet.
    const mediaRe = /@media\s+([^{}]*)\{/g;
    let m: RegExpExecArray | null;
    let foundPointerCoarse = false;
    while ((m = mediaRe.exec(CSS)) !== null) {
      const condition = m[1].replace(/\s+/g, '');
      if (condition.includes('pointer:coarse')) {
        foundPointerCoarse = true;
        break;
      }
    }
    expect(
      foundPointerCoarse,
      'the touch-reveal media query must list (pointer: coarse) in its condition, ' +
        'not only (hover: none) — otherwise coarse-pointer devices that still ' +
        'report hover (e.g. touch laptops) keep a dead, non-tappable trigger',
    ).toBe(true);
  });

  it('makes the ⋮ button fully visible (opacity:1) at rest on touch', () => {
    const body = coarsePointerMediaQueryBody();
    expect(body, 'a coarse-pointer media query must exist').not.toBeNull();
    const btn = declarationsIn(body!, /\.row-menu-btn(?![\w[#.:])/);
    expect(
      btn,
      'a .row-menu-btn rule must exist inside the coarse-pointer media query',
    ).not.toBeNull();
    expect(/opacity\s*:\s*1/.test(btn!), 'opacity:1 at rest on touch').toBe(true);
  });

  it('makes the ⋮ button directly tappable (pointer-events:auto) at rest on touch', () => {
    // This is the crux of the touch bug: the base rule sets pointer-events:none,
    // which blocks ALL pointer input (including touch taps). On a coarse-pointer
    // device the button MUST be pointer-events:auto AT REST — otherwise it is
    // visible-but-dead and the hover/focus reveal conditions can never fire
    // (there is no way to first "reveal" something whose input is blocked).
    const body = coarsePointerMediaQueryBody();
    expect(body, 'a coarse-pointer media query must exist').not.toBeNull();
    const btn = declarationsIn(body!, /\.row-menu-btn(?![\w[#.:])/);
    expect(
      btn,
      'a .row-menu-btn rule must exist inside the coarse-pointer media query',
    ).not.toBeNull();
    expect(
      /pointer-events\s*:\s*auto/.test(btn!),
      'pointer-events:auto at rest on touch (the base pointer-events:none would block taps)',
    ).toBe(true);
  });

  it('does not regress the desktop base rule (still suppressed at rest)', () => {
    // The touch fix must be ADDITIVE — a media-query override — not a change to
    // the base rule, so desktop keeps its reveal-on-hover aesthetic. The base
    // rule must still set pointer-events:none and an opacity < 1 at rest.
    const btn = ruleDeclarations(/\.row-menu-btn(?![\w[#.:])/)!;
    expect(/pointer-events\s*:\s*none/.test(btn), 'base pointer-events:none unchanged').toBe(true);
    const op = btn.match(/opacity\s*:\s*([0-9.]+)/);
    expect(op, 'opacity declared on the base rule').not.toBeNull();
    expect(Number(op![1]), 'base opacity stays < 1 at rest on desktop').toBeLessThan(1);
  });
});

describe('src/app.css — row action dropdown menu (.row-menu)', () => {
  it('is a fixed-position, flex-column overlay that floats above the scroll container', () => {
    const menu = ruleDeclarations(/\.row-menu/);
    expect(menu, 'a base .row-menu { ... } rule must exist').not.toBeNull();
    // position:fixed so a menu placed at viewport clientX/clientY is NOT clipped
    // by the .results{overflow:auto} scroll container and layers correctly.
    expect(/position\s*:\s*fixed/.test(menu!), 'position:fixed').toBe(true);
    // Must sit above the sticky th (which has z-index:1).
    const z = menu!.match(/z-index\s*:\s*(\d+)/);
    expect(z, 'z-index declared').not.toBeNull();
    expect(Number(z![1]), 'z-index must be > 1 to sit above the sticky th').toBeGreaterThan(1);
    expect(/display\s*:\s*flex/.test(menu!), 'display:flex').toBe(true);
    expect(/flex-direction\s*:\s*column/.test(menu!), 'flex-direction:column').toBe(true);
    expect(/min-width\s*:\s*140px/.test(menu!), 'min-width:140px').toBe(true);
    expect(/box-shadow\s*:/.test(menu!), 'box-shadow present').toBe(true);
    expect(/background\s*:\s*#2d2d30/.test(menu!), 'background:#2d2d30').toBe(true);
    expect(/border-radius\s*:\s*4px/.test(menu!), 'border-radius:4px').toBe(true);
  });

  it('is actually hidden when [hidden] despite the author display:flex (critical override)', () => {
    // Same class of bug as .browser-dialog above: the menu closes via the HTML
    // `hidden` attribute (UA [hidden]{display:none}), but the author
    // `.row-menu{display:flex}` rule overrides the UA sheet and would keep a
    // closed menu visible. An explicit `.row-menu[hidden]{display:none}` rule
    // (higher specificity than the base) MUST exist to defeat that.
    const hidden = ruleDeclarations(/\.row-menu\[hidden\]/);
    expect(hidden, 'a .row-menu[hidden] { ... } override rule must exist').not.toBeNull();
    expect(/display\s*:\s*none/.test(hidden!), '.row-menu[hidden] must set display:none').toBe(
      true,
    );
  });
});

describe('src/app.css — row menu items (.row-menu .btn)', () => {
  it('flattens .btn into a full-width, left-aligned menu-item look', () => {
    const item = ruleDeclarations(/\.row-menu \.btn/);
    expect(item, 'a .row-menu .btn { ... } rule must exist').not.toBeNull();
    expect(/background\s*:\s*none/.test(item!), 'background:none').toBe(true);
    expect(/border\s*:\s*none/.test(item!), 'border:none').toBe(true);
    expect(/color\s*:\s*#e6e6e6/.test(item!), 'color:#e6e6e6').toBe(true);
    expect(/width\s*:\s*100%/.test(item!), 'width:100%').toBe(true);
    expect(/text-align\s*:\s*left/.test(item!), 'text-align:left').toBe(true);
    expect(/justify-content\s*:\s*flex-start/.test(item!), 'justify-content:flex-start').toBe(true);
  });

  it('shows a hover background on menu items', () => {
    const hover = ruleDeclarations(/\.row-menu \.btn:hover/);
    expect(hover, 'a .row-menu .btn:hover rule must exist').not.toBeNull();
    expect(/background\s*:\s*#3a3d41/.test(hover!), 'hover background #3a3d41').toBe(true);
  });
});

